// 1. Get Current IST Time
const now = new Date();
const istNow = new Date(now.toLocaleString("en-US", { timeZone: "Asia/Kolkata" }));
const currentMinutes = istNow.getHours() * 60 + istNow.getMinutes();

const output = [];

// 2. Loop through all rows
for (const item of $input.all()) {
    let timeInput = item.json.Time;

    // Skip empty times
    if (!timeInput) continue;

    let scheduleMinutes = 0;
    let isParsed = false;

    // --- PARSING LOGIC (The Fix) ---

    // Case A: Excel Serial Number (e.g. 0.375) or pure Number
    if (typeof timeInput === 'number') {
        // 0.5 = 12:00 PM (0.5 * 24 * 60 minutes)
        const totalMinutes = Math.round(timeInput * 24 * 60);
        scheduleMinutes = totalMinutes % 1440; // Ensure it fits in 24 hours
        isParsed = true;
    } 
    // Case B: String formats (e.g. "09:00", "9:00 AM")
    else {
        let timeStr = String(timeInput).trim();

        // Try AM/PM Match (e.g. "9:00 AM")
        const amPmMatch = timeStr.match(/(\d{1,2}):(\d{2})\s*(AM|PM)/i);
        if (amPmMatch) {
            let h = parseInt(amPmMatch[1]);
            let m = parseInt(amPmMatch[2]);
            let p = amPmMatch[3].toUpperCase();

            if (p === 'PM' && h < 12) h += 12;
            if (p === 'AM' && h === 12) h = 0;

            scheduleMinutes = (h * 60) + m;
            isParsed = true;
        } 
        // Try Standard 24H Match (e.g. "14:30")
        else {
            const parts = timeStr.split(':');
            if (parts.length >= 2) {
                scheduleMinutes = (parseInt(parts[0]) * 60) + parseInt(parts[1]);
                isParsed = true;
            }
        }
    }

    // If we couldn't parse it, skip this row
    if (!isParsed) continue;

    // --- MATCHING LOGIC ---

    const diff = scheduleMinutes - currentMinutes;

    // Reminder: Trigger 1 to 5 minutes BEFORE
    // (e.g. Schedule 9:05, Current 9:00 -> Diff 5)
    if (diff >= 1 && diff <= 5) {
        output.push({ 
            json: { ...item.json, triggerType: "REMINDER" } 
        });
    }
    // Checkin: Trigger exactly at time or 1 minute late
    // (e.g. Schedule 9:00, Current 9:00 -> Diff 0)
    else if (diff >= -1 && diff <= 1) {
        output.push({ 
            json: { ...item.json, triggerType: "CHECKIN" } 
        });
    }
}

return output;

const currentEvents = [];
const processedKeys = new Set();

for (const item of $input.all()) {

  // Attendance events have EmployeeName
  if (item.json.EmployeeName) {
    currentEvents.push(item);
  }

  // ProcessedEvents rows have EventKey
  else if (item.json.EventKey) {
    processedKeys.add(item.json.EventKey);
  }

}

const output = [];

for (const event of currentEvents) {

  if (!processedKeys.has(event.json.EventKey)) {
    output.push(event);
  }

}

return output;

