const items = $input.all();

return items.map(item => {

  let output = item.json.output;

  output = output
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/\s*```$/, "")
    .trim();

  return {
    json: JSON.parse(output)
  };

});

function distance(lat1, lon1, lat2, lon2) {
  const R = 6371000;

  const toRad = deg => deg * Math.PI / 180;

  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);

  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(toRad(lat1)) *
    Math.cos(toRad(lat2)) *
    Math.sin(dLon / 2) ** 2;

  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));

  return R * c;
}

const items = $input.all();

return items.map(item => {

  const actualLat = Number(item.json.SharedLatitude);
  const actualLon = Number(item.json.SharedLongitude);

  const targetLat = Number(item.json.TargetLatitude);
  const targetLon = Number(item.json.TargetLongitude);

  const dist = distance(
    actualLat,
    actualLon,
    targetLat,
    targetLon
  );

  return {
    json: {
      ...item.json,
      Distance: Math.round(dist)
    }
  };

});
